content.text:
.root {
  background-color: var(--imf-ui-color-bg-main);

  box-shadow:
    var(--imf-ui-border-size-4) var(--imf-ui-border-size-4) 0px 0px
      color-mix(in oklch, var(--imf-ui-color-bg-primary) 20%, transparent),
    var(--imf-ui-border-size-5) var(--imf-ui-border-size-5) 0px 0px
      color-mix(in oklch, var(--imf-ui-color-bg-primary) 10%, transparent);

  /* prettier-ignore */
  border: var(--imf-ui-border-size-2) solid 
      color-mix(in oklch, var(--imf-ui-color-bg-primary) 50%, transparent);

  border-radius: var(--explorer-border-radius-default);
}

import { cx } from "@imfusion/web-ui";

import classes from "./elevation.module.css";

interface Props extends React.HTMLAttributes<HTMLDivElement> {}

export function Elevation({ className, children, ...rest }: Props) {
  return (
    <div {...rest} data-explorer-component="Elevation" className={cx(classes.root, className)}>
      {children}
    </div>
  );
}
